import SwiftUI

// MARK: - SVG Path Parser

private func tokenizeSVG(_ d: String) -> [String] {
    var tokens: [String] = []
    var current = ""
    for char in d {
        if char.isLetter {
            if !current.isEmpty { tokens.append(current); current = "" }
            tokens.append(String(char))
        } else if char == "-" {
            if !current.isEmpty { tokens.append(current) }
            current = "-"
        } else if char == " " || char == "," || char == "\n" || char == "\t" {
            if !current.isEmpty { tokens.append(current); current = "" }
        } else {
            current.append(char)
        }
    }
    if !current.isEmpty { tokens.append(current) }
    return tokens
}

private func buildCGPath(from tokens: [String]) -> CGPath {
    let path = CGMutablePath()
    var i = 0
    var cx: CGFloat = 0
    var cy: CGFloat = 0

    func next() -> CGFloat {
        guard i < tokens.count else { return 0 }
        let v = CGFloat(Double(tokens[i]) ?? 0)
        i += 1
        return v
    }

    while i < tokens.count {
        let cmd = tokens[i]; i += 1
        switch cmd {
        case "M":
            cx = next(); cy = next()
            path.move(to: CGPoint(x: cx, y: cy))
        case "C":
            let x1 = next(), y1 = next()
            let x2 = next(), y2 = next()
            cx = next(); cy = next()
            path.addCurve(to: CGPoint(x: cx, y: cy),
                          control1: CGPoint(x: x1, y: y1),
                          control2: CGPoint(x: x2, y: y2))
        case "L":
            cx = next(); cy = next()
            path.addLine(to: CGPoint(x: cx, y: cy))
        case "H":
            cx = next()
            path.addLine(to: CGPoint(x: cx, y: cy))
        case "V":
            cy = next()
            path.addLine(to: CGPoint(x: cx, y: cy))
        case "Z":
            path.closeSubpath()
        default:
            break
        }
    }
    return path
}

